import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface ReturnTrend {
  month: string;
  rate: number;
}

interface ReturnData {
  returnRate: {
    currentMonth: number;
    previousMonth: number;
    changePercent: number;
  };
  topReasons: { reason: string; count: number }[];
  monthlyReturnTrend: ReturnTrend[];
}

export default function Widget() {
  const data = response.data as ReturnData;
  const { returnRate, topReasons, monthlyReturnTrend } = data;
  const clipPathId = useId();
  const isPositiveChange = returnRate.changePercent >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              Return Rate
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#333' }}>
              {returnRate.currentMonth}%
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5}>
              {isPositiveChange ? (
                <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} />
              ) : (
                <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />
              )}
              <Typography variant="body2" sx={{ color: isPositiveChange ? '#10B981' : '#EF4444' }}>
                {isPositiveChange ? '+' : ''}
                {returnRate.changePercent}%
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#666', mb: 1 }}>
              Top Return Reasons
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {topReasons.map((reason, index) => (
                <Chip
                  key={index}
                  label={`${reason.reason} (${reason.count})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: monthlyReturnTrend.map((m) => m.rate),
                  color: '#FFC107',
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: monthlyReturnTrend.map((m) => m.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'rate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="rate"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
